    public double new21Game(int n, int k, int maxPts) {
        if (k == 0 || n >= k + maxPts - 1) return 1.0;
        double[] dp = new double[n + 1];
        dp[0] = 1.0;
        double window = 1.0;
        for (int i = 1; i <= n; i++) {
            dp[i] = window / maxPts;
            if (i < k) window += dp[i];
            if (i - maxPts >= 0 && i - maxPts < k) window -= dp[i - maxPts];
        }
        double res = 0.0;
        for (int i = k; i <= n; i++) res += dp[i];
        return res;
    }
}
